import{_ as e,o as a,c as i,a2 as n}from"./chunks/framework.CZqXuAiL.js";const k=JSON.parse('{"title":"Connection Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/detection-engine/conn-track.md","filePath":"openshield-xdp/detection-engine/conn-track.md","lastUpdated":1782455978000}'),s={name:"openshield-xdp/detection-engine/conn-track.md"};function o(d,t,r,c,l,h){return a(),i("div",null,[...t[0]||(t[0]=[n(`<h1 id="connection-tracking" tabindex="-1">Connection Tracking <a class="header-anchor" href="#connection-tracking" aria-label="Permalink to &quot;Connection Tracking&quot;">​</a></h1><p>Drops blind TCP responses — packets that claim to be part of a connection the server never initiated.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Each IP&#39;s <code>ip_stats</code> struct stores <code>last_syn_seen_ns</code> — the timestamp of the most recent SYN from that IP. On every TCP packet:</p><ol><li>If the packet is a SYN, update <code>last_syn_seen_ns</code> to <code>now</code></li><li>If the packet is an ACK (not SYN) and no SYN was seen within <code>ct_syn_timeout_sec</code>, drop it as a blind ACK</li><li>If the packet is a RST and no SYN was ever seen, drop it as a blind RST</li></ol><h2 id="what-it-catches" tabindex="-1">What it catches <a class="header-anchor" href="#what-it-catches" aria-label="Permalink to &quot;What it catches&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Attack</th><th>Signature</th><th>Why</th></tr></thead><tbody><tr><td>Blind SYN-ACK flood</td><td>ACK without prior SYN</td><td>Attacker sends ACKs to an open port, server wastes resources</td></tr><tr><td>Stale SYN-ACK</td><td>SYN older than timeout</td><td>Legitimate SYN timed out, returning ACK is now invalid</td></tr><tr><td>Blind RST flood</td><td>RST without prior SYN</td><td>Attacker tries to tear down connections</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">static</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enable_connection_tracking</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Off by default</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ct_syn_timeout_sec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # Max age of last SYN</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">When to disable</p><p>Connection tracking has a small edge case: long-lived connections where the server sends a SYN-ACK first (rare). Most deployments can safely enable it.</p></div><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limitation</th><th>Detail</th></tr></thead><tbody><tr><td>Per-IP, not per-connection</td><td>Tracks last SYN per source IP, not per 5-tuple</td></tr><tr><td>No state machine</td><td>Doesn&#39;t track connection state beyond SYN timestamp</td></tr><tr><td>Legitimate SYN-ACK</td><td>Server-originated connections (e.g., health checks) may trigger false positives</td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related pages&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/detection-engine/rate-based">Rate-Based Detection</a> · <a href="/pingless-studios-docs/openshield-xdp/detection-engine/pipeline">Pipeline</a></p>`,14)])])}const g=e(s,[["render",o]]);export{k as __pageData,g as default};
